(function(){"use strict";function inferGenre(game){if(game.genre)return game.genre;if(window.wgpTasteProfile&&window.wgpTasteProfile.inferGenre){return window.wgpTasteProfile.inferGenre(game)}return"Arcade"}function genreBoost(genre,signature){if(!signature||!signature.length)return 0;for(var i=0;i<signature.length;i++){if(signature[i].genre===genre){return Math.round(signature[i].pct*.35)}}return 0}function sentimentBoost(rating){var r=parseFloat(rating);if(isNaN(r))return 0;if(r>=4.7)return 5;if(r>=4.3)return 3;if(r>=4)return 1;return 0}function matchGame(game){var sig=window.wgpTasteProfile&&window.wgpTasteProfile.getSignature?window.wgpTasteProfile.getSignature():[];var genre=inferGenre(game);var score=60+genreBoost(genre,sig)+sentimentBoost(game.rating);score=Math.max(0,Math.min(100,score));var reason;for(var i=0;i<sig.length;i++){if(sig[i].genre===genre){reason="Because you love "+genre;break}}if(!reason)reason="Popular with players like you";return{score,reason,genre}}function rankGames(games){if(!games||!games.length)return[];return games.slice().map(function(g){var m=matchGame(g);return{game:g,score:m.score,reason:m.reason,genre:m.genre}}).sort(function(a,b){return b.score-a.score})}window.wgpVerdictEngine={matchGame,rankGames}})();
